```
class Codec:
    def serialize(self, root):
        if root is None: return ""
        children_encoding = " ".join([self.serialize(child) for child in root.children])
        return "[" + str(root.val) + children_encoding + "]"

    def deserialize(self, data):
        class Parser:
            def __init__(self, tokens):
                self.tokens = tokens
                self.idx = 0

            def lookahead(self): return self.tokens[self.idx]
            def consume(self):
                val = self.lookahead()
                self.idx += 1
                return val

            def parse(self):
                self.consume() # consume [
                acc = Node(int(self.consume()), []) # consume val

                while self.lookahead() == "[":
                    acc.children.append(self.parse())

                self.consume() # consume ]
                return acc

        tokens = re.findall(r"\[|\]|\d+", data)
        if not tokens: return None # handle base case
        return Parser(tokens).parse()
